    tracker.reset()
    progress = tracker.get_progress()
    assert progress["run_id"] == 0
    assert progress["completed_phases"] == []
    assert tracker.get_run_history() == []
    assert tracker.get_last_checkpoint() is None
    
    print("✅ test_progress_tracker_reset PASSED")


