    """Per-source uncertainty values are clamped to [0, 1] in feedback signals."""
    import torch
    from aeon_core import AEONDeltaV3

    class _MockModel:
        class config:
            diversity_collapse_threshold = 0.3
            lipschitz_target = 0.85
