def test_adaptive_coherence_trend_warmup():
    """Coherence trend warm-up should adapt based on variance:
    lower variance → fewer passes needed, higher variance → more passes."""
    from aeon_core import (
        UnifiedCognitiveCycle, ConvergenceMonitor,
        CausalProvenanceTracker,
    )

    cm = ConvergenceMonitor()
    prov = CausalProvenanceTracker()

    ucc = UnifiedCognitiveCycle(
        convergence_monitor=cm,
        coherence_verifier=None,
        error_evolution=None,
        metacognitive_trigger=None,
        provenance_tracker=prov,
    )

    states = {"module_a": torch.randn(1, 16)}

    # Feed consistent high coherence deficits (low variance scenario)
    for _ in range(2):
        ucc.evaluate(
            subsystem_states=states,
            delta_norm=0.1,
            uncertainty=0.1,
        )

    # After 2 passes with consistent data and low variance, the EMA should
    # have been computed; the variance tracker should exist
    assert hasattr(ucc, '_coherence_trend_var_ema'), (
        "UCC should have _coherence_trend_var_ema attribute"
    )
    assert ucc._coherence_trend_count == 2, (
        f"Expected 2 passes, got {ucc._coherence_trend_count}"
    )

    # Now feed several high-deficit passes
    for _ in range(3):
        result = ucc.evaluate(
            subsystem_states=states,
            delta_norm=0.1,
            uncertainty=0.1,
        )

    # After 5 passes, trend tracking should be active
    trend_info = result.get('coherence_trend', {})
    assert trend_info.get('pass_count', 0) == 5, (
        f"Expected 5 passes, got {trend_info.get('pass_count', 0)}"
    )
    print("✅ test_adaptive_coherence_trend_warmup PASSED")


def test_counterfactual_verification_loss_in_compute_loss():
    """compute_loss includes counterfactual_verification_loss when the
    CounterfactualVerificationGate detects causal prediction divergence."""
    from aeon_core import AEONConfig, AEONDeltaV3
    import torch

    config = AEONConfig(
        hidden_dim=32, z_dim=32, vq_embedding_dim=32,
        num_pillars=8, vocab_size=256,
        enable_safety_guardrails=False,
        enable_catastrophe_detection=False,
        enable_quantum_sim=False,
        enable_metacognitive_recursion=True,
        enable_error_evolution=True,
        enable_causal_trace=True,
    )
    model = AEONDeltaV3(config)
    model.eval()

    B = 2
    # Construct a minimal outputs dict that compute_loss can process
    outputs = {
        'logits': torch.randn(B, config.seq_length, config.vocab_size),
        'core_state': torch.randn(B, config.hidden_dim),
        'psi_0': torch.randn(B, config.z_dim),
        'vq_loss': torch.tensor(0.0),
        'safety_score': torch.ones(B, 1),
        'factors': torch.randn(B, config.num_pillars),
        # Inject a counterfactual divergence
        'counterfactual_gate_results': {'divergence': 0.7},
    }
    targets = torch.randint(0, config.vocab_size, (B, config.seq_length))
    loss_dict = model.compute_loss(outputs, targets)

    assert 'counterfactual_verification_loss' in loss_dict, (
        "compute_loss must return counterfactual_verification_loss"
    )
    cf_loss = loss_dict['counterfactual_verification_loss']
    assert cf_loss.item() > 0.0, (
        "counterfactual_verification_loss should be > 0 when divergence is 0.7"
    )
    print("✅ test_counterfactual_verification_loss_in_compute_loss PASSED")


